  1	import React, { FC, FormEvent, useContext, useEffect, useMemo, useState } from 'react';
  2	import { Helmet } from 'react-helmet';
  3	import { useNavigate } from 'react-router-dom-v5-compat';
  4	import axios from 'axios';
  5	import cx from 'classnames';
  6	
  7	import {
  8	  modelToGroupVersionKind,
  9	  PersistentVolumeClaimModel,
 10	  StorageClassModel,
 11	  TemplateModel,
 12	  V1Template,
 13	} from '@kubevirt-ui/kubevirt-api/console';
 14	import DataVolumeModel from '@kubevirt-ui/kubevirt-api/console/models/DataVolumeModel';
 15	import { V1beta1DataVolume } from '@kubevirt-ui/kubevirt-api/containerized-data-importer/models';
 16	import { IoK8sApiStorageV1StorageClass } from '@kubevirt-ui/kubevirt-api/kubernetes';
 17	import ExternalLink from '@kubevirt-utils/components/ExternalLink/ExternalLink';
 18	import { documentationURL } from '@kubevirt-utils/constants/documentation';
 19	import { createUploadPVC } from '@kubevirt-utils/hooks/useCDIUpload/utils';
 20	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 21	import {
 22	  TEMPLATE_TYPE_BASE,
 23	  TEMPLATE_TYPE_LABEL,
 24	  TEMPLATE_VM_COMMON_NAMESPACE,
 25	} from '@kubevirt-utils/resources/template';
 26	import {
 27	  K8sVerb,
 28	  useAccessReview,
 29	  useActiveNamespace,
 30	  useK8sWatchResource,
 31	  WatchK8sResource,
 32	} from '@openshift-console/dynamic-plugin-sdk';
 33	import { ActionGroup, Alert, Button, ButtonVariant } from '@patternfly/react-core';
 34	
 35	import useBaseImages from '../hooks/useBaseImages';
 36	import useMultipleAccessReviews from '../hooks/useMultipleAccessReviews';
 37	import { CDI_UPLOAD_OS_URL_PARAM, CDI_UPLOAD_URL_BUILDER, uploadErrorType } from '../utils/consts';
 38	import { CDIUploadContext } from '../utils/context';
 39	import { getName, getNamespace, getPVCNamespace } from '../utils/selectors';
 40	import { resourcePath } from '../utils/utils';
 41	
 42	import UploadPVCButtonBar from './UploadPVCButtonBar';
 43	import UploadPVCForm from './UploadPVCForm';
 44	import UploadPVCFormStatus from './UploadPVCFormStatus';
 45	
 46	const templatesResource: WatchK8sResource = {
 47	  groupVersionKind: modelToGroupVersionKind(TemplateModel),
 48	  isList: true,
 49	  namespace: TEMPLATE_VM_COMMON_NAMESPACE,
 50	  optional: true,
 51	  selector: {
 52	    matchLabels: { [TEMPLATE_TYPE_LABEL]: TEMPLATE_TYPE_BASE },
 53	  },
 54	};
 55	const UploadPVCPage: FC = () => {
 56	  const { t } = useKubevirtTranslation();
 57	  const [isSubmitting, setIsSubmitting] = useState(false);
 58	  const [isCheckingCertificate, setCheckingCertificate] = useState(false);
 59	  const [disableFormSubmit, setDisableFormSubmit] = useState(false);
 60	  const [fileValue, setFileValue] = useState<File>(null);
 61	  const [fileName, setFileName] = useState('');
 62	  const [fileNameExtension, setFileNameExtension] = useState('');
 63	  const [isFileRejected, setIsFileRejected] = useState(false);
 64	  const [error, setError] = useState<string>('');
 65	  const [isAllocating, setIsAllocating] = useState(false);
 66	  const [dvObj, setDvObj] = useState<V1beta1DataVolume>(null);
 67	  const [commonTemplates, loadedTemplates, errorTemplates] =
 68	    useK8sWatchResource<V1Template[]>(templatesResource);
 69	  const navigate = useNavigate();
 70	  const goldenNamespacesResources = useMemo(() => {
 71	    const goldenNamespaces = [
 72	      ...new Set(
 73	        (commonTemplates || []).map((template) => getPVCNamespace(template)).filter((ns) => !!ns),
 74	      ),
 75	    ];
 76	
 77	    return goldenNamespaces.map((ns) => ({
 78	      group: DataVolumeModel.apiGroup,
 79	      namespace: ns,
 80	      resource: DataVolumeModel.plural,
 81	      verb: 'create' as K8sVerb,
 82	    }));
 83	  }, [commonTemplates]);
 84	
 85	  const [goldenAccessReviews, rbacLoading] = useMultipleAccessReviews(
 86	    goldenNamespacesResources,
 87	    null,
 88	  );
 89	  const allowedTemplates = commonTemplates.filter((tmp) =>
 90	    goldenAccessReviews.some(
 91	      (accessReview) =>
 92	        accessReview.allowed && accessReview.resourceAttributes.namespace === getPVCNamespace(tmp),
 93	    ),
 94	  );
 95	
 96	  const [goldenPvcs, loadedPvcs, errorPvcs] = useBaseImages(allowedTemplates);
 97	  const { uploadData, uploadProxyURL, uploads } = useContext(CDIUploadContext);
 98	  const [scAllowed, scAllowedLoading] = useAccessReview({
 99	    group: StorageClassModel.apiGroup,
100	    resource: StorageClassModel.plural,
101	    verb: 'list',
102	  });
103	  const [storageClasses, scLoaded] = useK8sWatchResource<IoK8sApiStorageV1StorageClass[]>(
104	    scAllowed
105	      ? {
106	          groupVersionKind: modelToGroupVersionKind(StorageClassModel),
107	          isList: true,
108	          namespaced: false,
109	        }
110	      : null,
111	  );
112	
113	  const [initialNamespace] = useActiveNamespace();
114	  const namespace = getNamespace(dvObj) || initialNamespace;
115	  const urlParams = new URLSearchParams(window.location.search);
116	  const osParam = urlParams.get(CDI_UPLOAD_OS_URL_PARAM);
117	  const title = t('Upload data to Persistent Volume Claim');
118	  const fileNameExtText = fileNameExtension
119	    ? t('Detected file extension is {{fileNameExtension}}', { fileNameExtension })
120	    : t('No file extension detected');
121	
122	  const save = (e: FormEvent<EventTarget>) => {
123	    e.preventDefault();
124	    if (!fileName) {
125	      setError(uploadErrorType.MISSING);
126	    } else {
127	      // checking valid certificate for proxy
128	      setCheckingCertificate(true);
129	      axios
130	        .get(CDI_UPLOAD_URL_BUILDER(uploadProxyURL))
131	        .catch((catchError) => {
132	          setCheckingCertificate(false);
133	          // the GET request will return an error everytime, but it will be undefined only if the certificate is invalid.
134	          if (catchError?.response?.data === undefined) {
135	            throw new Error(uploadErrorType.CERT);
136	          }
137	        })
138	        .then(() => {
139	          setError('');
140	          setIsAllocating(true);
141	          setIsSubmitting(true);
142	          return createUploadPVC(dvObj);
143	        })
144	        .then(({ token }) => {
145	          setIsAllocating(false);
146	          uploadData({
147	            file: fileValue,
148	            namespace,
149	            pvcName: getName(dvObj),
150	            token,
151	          });
152	        })
153	        .catch((err) => {
154	          setIsAllocating(false);
155	          setError(err?.message || uploadErrorType.ALLOCATE);
156	        });
157	    }
158	  };
159	
160	  const handleFileChange = (_, value) => {
161	    setFileValue(value);
162	
163	    setIsFileRejected(false);
164	    setError('');
165	  };
166	
167	  const handleFileNameChange = (_, filename: string) => {
168	    setFileName(filename);
169	    setFileNameExtension(/[.][^.]+$/.exec(filename)?.toString());
170	  };
171	
172	  useEffect(() => {
173	    if (errorTemplates || errorPvcs) {
174	      setError(errorTemplates?.message || errorPvcs?.message);
175	    }
176	  }, [errorTemplates, errorPvcs]);
177	
178	  return (
179	    <>
180	      <Helmet>
181	        <title>{title}</title>
182	      </Helmet>
183	      <div
184	        className={cx('co-m-pane__body co-m-pane__form', {
185	          'kv--create-upload__hide': isSubmitting,
186	        })}
187	      >
188	        <h1 className="co-m-pane__heading co-m-pane__heading--baseline">
189	          <div className="co-m-pane__name">{title}</div>
190	        </h1>
191	        <form className="co-m-pane__body-group" onSubmit={save}>
192	          <UploadPVCForm
193	            commonTemplates={allowedTemplates}
194	            fileName={fileName}
195	            fileValue={fileValue}
196	            goldenPvcs={goldenPvcs}
197	            handleFileChange={handleFileChange}
198	            handleFileNameChange={handleFileNameChange}
199	            isLoading={!loadedTemplates}
200	            ns={initialNamespace}
201	            onChange={setDvObj}
202	            osParam={osParam}
203	            setDisableFormSubmit={setDisableFormSubmit}
204	            setIsFileRejected={setIsFileRejected}
205	            storageClasses={storageClasses}
206	          />
207	          <UploadPVCButtonBar
208	            inProgress={
209	              rbacLoading ||
210	              scAllowedLoading ||
211	              !scLoaded ||
212	              !loadedTemplates ||
213	              !loadedPvcs ||
214	              isCheckingCertificate
215	            }
216	            errorMessage={error}
217	            uploadProxyURL={uploadProxyURL}
218	          >
219	            {isFileRejected && (
220	              <Alert isInline title={t('File type extension')} variant="warning">
221	                <p>
222	                  {t(
223	                    'Based on the file extension it seems like you are trying to upload a file which is not supported ({{fileNameExtText}}).',
224	                    { fileNameExtText },
225	                  )}
226	                </p>
227	                <p>
228	                  <ExternalLink
229	                    href={documentationURL.CDI_UPLOAD_SUPPORTED_TYPES}
230	                    text={t('Learn more about supported formats')}
231	                  />
232	                </p>
233	              </Alert>
234	            )}
235	            <ActionGroup className="pf-v6-c-form">
236	              <Button
237	                id="save-changes"
238	                isDisabled={disableFormSubmit || isCheckingCertificate}
239	                type="submit"
240	                variant={ButtonVariant.primary}
241	              >
242	                {t('Upload')}
243	              </Button>
244	              <Button onClick={() => navigate(-1)} type="button" variant="secondary">
245	                {t('Cancel')}
246	              </Button>
247	            </ActionGroup>
248	          </UploadPVCButtonBar>
249	        </form>
250	      </div>
251	      <UploadPVCFormStatus
252	        onErrorClick={() => {
253	          setIsSubmitting(false);
254	          setError('');
255	        }}
256	        onSuccessClick={() =>
257	          navigate(resourcePath(PersistentVolumeClaimModel, getName(dvObj), namespace))
258	        }
259	        upload={uploads?.find(
260	          (upl) => upl?.pvcName === getName(dvObj) && upl?.namespace === namespace,
261	        )}
262	        allocateError={error}
263	        dataVolume={dvObj}
264	        isAllocating={isAllocating}
265	        isSubmitting={isSubmitting}
266	        onCancelClick={() => navigate(resourcePath(PersistentVolumeClaimModel))}
267	      />
268	    </>
269	  );
270	};
271	
272	export default UploadPVCPage;

